import { NextResponse } from "next/server";
import { createWorker } from "tesseract.js";
import * as pdfjsLib from "pdfjs-dist";
import fs from "fs/promises";
import path from "path";
import { createCanvas } from "canvas";

pdfjsLib.GlobalWorkerOptions.workerSrc = path.join(
  process.cwd(),
  "public/pdfjs/pdf.worker.js"
);


export async function POST(req: Request) {
  try {
    const formData = await req.formData();
    const file = formData.get("file") as File;
    if (!file)
      return NextResponse.json({ error: "No file uploaded" }, { status: 400 });

    // Save the uploaded file
    const uploadDir = path.join(process.cwd(), "public/uploads");
    await fs.mkdir(uploadDir, { recursive: true });
    const pdfPath = path.join(uploadDir, file.name);
    const buffer = Buffer.from(await file.arrayBuffer());
    await fs.writeFile(pdfPath, buffer);

    console.log("PDF saved at:", pdfPath);

    // Extract text from PDF
    const extractedText = await extractTextFromPDF(pdfPath);
    return NextResponse.json({ text: extractedText });
  } catch (error) {
    console.error("OCR Extraction Error:", error);
    return NextResponse.json(
      { error: "PDF processing failed" },
      { status: 500 }
    );
  }
}

async function extractTextFromPDF(pdfPath: string): Promise<string> {
  try {
    const data = new Uint8Array(await fs.readFile(pdfPath)); // ✅ Fix Uint8Array issue
    const pdf = await pdfjsLib.getDocument({ data }).promise;
    console.log(`PDF Loaded Successfully: ${pdf.numPages} pages found`);

    const imagePaths = await convertPDFToImages(pdf);
    return await extractTextFromImages(imagePaths);
  } catch (error) {
    console.error("Error extracting text from PDF:", error);
    throw new Error("PDF processing failed");
  }
}

async function convertPDFToImages(pdf: any): Promise<string[]> {
  const uploadDir = path.join(process.cwd(), "public/uploads");
  await fs.mkdir(uploadDir, { recursive: true });

  let imagePaths: string[] = [];

  for (let pageNum = 1; pageNum <= pdf.numPages; pageNum++) {
    const page = await pdf.getPage(pageNum);
    const viewport = page.getViewport({ scale: 2.0 });

    const canvas = createCanvas(viewport.width, viewport.height);
    const context = canvas.getContext("2d");

    const renderContext = { canvasContext: context, viewport };
    await page.render(renderContext).promise;

    const imagePath = path.join(uploadDir, `page-${pageNum}.png`);
    const buffer = canvas.toBuffer("image/png");
    await fs.writeFile(imagePath, buffer);

    console.log(`Saved page ${pageNum} image at: ${imagePath}`);
    imagePaths.push(imagePath);
  }

  return imagePaths;
}

async function extractTextFromImages(imagePaths: string[]): Promise<string> {
  const worker = await createWorker({
    workerPath: path.resolve(
      process.cwd(),
      "node_modules/tesseract.js/src/worker-script/node/index.js"
    ),
    langPath: path.resolve(
      process.cwd(),
      "node_modules/tesseract.js-core/tessdata"
    ),
    lang: "eng",
  });

  let fullText = "";

  for (const imagePath of imagePaths) {
    const { data } = await worker.recognize(imagePath);
    fullText += data.text + "\n";
    console.log(`Extracted text from image: ${imagePath}`);
  }

  await worker.terminate();
  return fullText;
}
